package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.Excluder;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.util.List;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;
  private ExclusionStrategy mockStrategy;
  private Excluder initialExcluder;

  @BeforeEach
  void setUp() throws Exception {
    gsonBuilder = new GsonBuilder();

    // Access private field 'excluder' to get initial Excluder instance
    Field excluderField = GsonBuilder.class.getDeclaredField("excluder");
    excluderField.setAccessible(true);
    initialExcluder = (Excluder) excluderField.get(gsonBuilder);

    mockStrategy = mock(ExclusionStrategy.class);
  }

  @Test
  void addDeserializationExclusionStrategy_shouldThrowNullPointerException_whenStrategyIsNull() {
    assertThrows(NullPointerException.class, () -> gsonBuilder.addDeserializationExclusionStrategy(null));
  }

  @Test
  void addDeserializationExclusionStrategy_shouldUpdateExcluderWithGivenStrategy() throws Exception {
    try (MockedStatic<Objects> objectsMockedStatic = Mockito.mockStatic(Objects.class)) {
      // Mock Objects.requireNonNull to call real method (to keep NPE behavior)
      objectsMockedStatic.when(() -> Objects.requireNonNull(mockStrategy)).thenCallRealMethod();

      // Spy on initialExcluder to verify withExclusionStrategy call
      Excluder spyExcluder = spy(initialExcluder);

      // Replace excluder field with spyExcluder
      Field excluderField = GsonBuilder.class.getDeclaredField("excluder");
      excluderField.setAccessible(true);
      excluderField.set(gsonBuilder, spyExcluder);

      // Mock withExclusionStrategy to return a new Excluder instance
      Excluder returnedExcluder = mock(Excluder.class);
      doReturn(returnedExcluder).when(spyExcluder).withExclusionStrategy(mockStrategy, false, true);

      GsonBuilder returnedBuilder = gsonBuilder.addDeserializationExclusionStrategy(mockStrategy);

      // Verify Objects.requireNonNull called
      objectsMockedStatic.verify(() -> Objects.requireNonNull(mockStrategy));

      // Verify withExclusionStrategy called with correct args
      verify(spyExcluder).withExclusionStrategy(mockStrategy, false, true);

      // Verify excluder field updated to returnedExcluder
      assertSame(returnedExcluder, excluderField.get(gsonBuilder));

      // Verify the method returns the same GsonBuilder instance
      assertSame(gsonBuilder, returnedBuilder);
    }
  }
}
